UPDATE t_p45929761_bold_move_project.ai_system_prompt
SET content = REPLACE(content,
E'КРИТИЧЕСКИ ВАЖНО — ОДИН ТОВАР НА НЕСКОЛЬКО СТЕН:',
E'КРИТИЧЕСКИ ВАЖНО — КОМАНДА ЗАМЕНЫ/РЕДАКТИРОВАНИЯ:\nЕсли монтажник говорит «убери», «замени», «поменяй», «вместо», «удали» — это команда редактирования.\nВОЗВРАЩАЙ ТОЛЬКО изменённые позиции, НЕ весь список заново.\nПример: «снизу убираем ПК-14 и теневой, ставим стеновой» →\n  Верни ТОЛЬКО: {\"name\":\"Стеновой алюминиевый\",\"qty\":2.5,\"wall\":\"bottom\"}\n  НЕ возвращай полотно, другие профили и прочее — только то что меняется.\nЕсли надо удалить без замены — верни пустой массив items: []\n\nКРИТИЧЕСКИ ВАЖНО — ОДИН ТОВАР НА НЕСКОЛЬКО СТЕН:')
WHERE id = 1